import {
    PdfViewer, Toolbar as Tool, Magnification, Navigation, LinkAnnotation, BookmarkView,
    ThumbnailView, Print, TextSearch, Annotation, FormFields, FormDesigner, PageOrganizer
} from '@syncfusion/ej2-pdfviewer';
import { Message, Severity } from '@syncfusion/ej2-notifications';
import { DropDownList } from '@syncfusion/ej2-dropdowns';
import { AsyncSettingsModel, NumericTextBox, SuccessEventArgs, Uploader } from '@syncfusion/ej2-inputs';
import { TextBox } from '@syncfusion/ej2-inputs';
import { CheckBox } from '@syncfusion/ej2-buttons';
import { Button } from '@syncfusion/ej2-buttons';
import { MultiSelect, CheckBoxSelection } from '@syncfusion/ej2-dropdowns';
import { Toolbar } from '@syncfusion/ej2-navigations';
import { createElement, isNullOrUndefined, select, selectAll } from '@syncfusion/ej2-base';
import { DatePicker } from '@syncfusion/ej2-calendars';
// tslint:disable-next-line:max-line-length
PdfViewer.Inject(FormDesigner, FormFields, Tool, Magnification, Navigation, LinkAnnotation, Annotation, BookmarkView, ThumbnailView, Print, TextSearch, PageOrganizer);
MultiSelect.Inject(CheckBoxSelection);




    
    const leftPad = (str: string, length: number, padChar: string): string => {
        while (str.length < length) {
            str = padChar + str;
        }
        return str;
    }

    const formatDate = (inputDate: Date): string => {
        const month = leftPad(String(inputDate.getMonth() + 1), 2, '0');
        const date = leftPad(String(inputDate.getDate()), 2, '0');
        const year = String(inputDate.getFullYear()).slice(-2);

        return `${month}-${date}-${year}`;
    }
    type CheckboxFields = 'signer' | 'reason' | 'location' | 'date';
    const displayModes: string[] = ['Image only', 'With signer details', 'Signer details only'];
    const digestAlgorithms: string[] = ['SHA1', 'SHA256', 'SHA384', 'SHA512', 'RIPEMD160'];
    const defaultDescriptionValues: Record<CheckboxFields, string> = {
        signer: 'James Carter',
        reason: 'I am the Author',
        location: 'Austin',
        date: formatDate(new Date())
    }
    let descriptionCheckboxes: Record<CheckboxFields, CheckBox> = {
        signer: null,
        reason: null,
        location: null,
        date: null
    };
    let descriptionTextboxes: Record<CheckboxFields, (TextBox | DatePicker)> = {
        signer: null,
        reason: null,
        location: null,
        date: null
    };
    let activeTab: number = 0;
    let x: number = 24;
    let y: number = 12;
    let width: number = 200;
    let height: number = 120;
    let displayMode: string = displayModes[1];
    let signatureType: string = 'CAdES';
    let digestAlgorithm: string = digestAlgorithms[1];
    let fileName: string = 'invisible-digital-signature';
    let downloadFileName: string = 'invisible-digital-signature';
    let documentData: string = '';
    const uploaderApiPath: AsyncSettingsModel = {
        saveUrl: 'http://localhost:62527/api/FileUploader/Save',
        removeUrl: 'http://localhost:62527/api/FileUploader/Remove'
    }
    const createNewGroup: HTMLElement = document.getElementById('visibleSign_createNew_exclusive') as HTMLDivElement;
    const existingFieldGroup: HTMLElement = document.getElementById('visibleSign_existingField_exclusive') as HTMLDivElement;
    const createNewHeader: HTMLElement = document.getElementById('visibleSign_header_createNew') as HTMLDivElement;
    createNewHeader.onclick = () => setActiveTab(0);
    const existingFieldHeader: HTMLElement = document.getElementById('visibleSign_header_existingField') as HTMLDivElement;
    existingFieldHeader.onclick = () => setActiveTab(1);

    // tslint:disable-next-line:max-line-length
    const defaultSignImage = "data:image/png;base64,";
    let imageUrls: string[] = [defaultSignImage];
    let selectedImageIndex: number = 0;

    const successMessageObj: Message = new Message({
        content: 'The document has been digitally signed and all the signatures are valid',
        severity: Severity.Success,
        visible: false
    });
    successMessageObj.appendTo('#visibleSign_message_success');
    const warningMessageObj: Message = new Message({
        content: 'The document has been digitally signed and at least one signature has problem',
        severity: Severity.Warning,
        showCloseIcon: true,
        visible: false
    });
    warningMessageObj.appendTo('#visibleSign_message_warning');
    const errorMessageObj: Message = new Message({
        content: 'The document has been digitally signed, but it has been modified since it was signed and at least one signature is invalid',
        severity: Severity.Error,
        showCloseIcon: true,
        visible: false
    });
    errorMessageObj.appendTo('#visibleSign_message_error');

    const viewer: PdfViewer = new PdfViewer({
        enableToolbar: false,
        enableAnnotationToolbar: false,
        enableNavigationToolbar: false,
        enableThumbnail: false,
        zoomMode: 'FitToPage',
        documentPath: 'https://cdn.syncfusion.com/content/pdf/visible-digital-signature.pdf',
        resourceUrl: 'https://cdn.syncfusion.com/ej2/27.2.2/dist/ej2-pdfviewer-lib'
    });
    viewer.appendTo('#visibleSign_pdfViewer');
    viewer.documentLoad = async (args) => {
        fileName = args.documentName;
        if (isNullOrUndefined(documentData) || !documentData.startsWith('data:application/pdf;base64,')) {
            documentData = await blobToBase64(await viewer.saveAsBlob());
        }
        const postData: any = {
            documentData: documentData
        };
        let options = {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(postData)
        };
        const apiUrl = 'http://localhost:62527/api/pdfviewer/ValidateSignature';
        fetch(apiUrl, options)
            .then(response => response.json())
            .then(body => {
                if (body.successVisible || body.warningVisible || body.errorVisible)
                    signDocumentButton.disabled = true;
                if (!body.downloadVisibility)
                    pdfViewerToolbar.items[0].disabled = false;
                if ((body.successVisible)) {
                    setTimeout(() => {
                        successMessageObj.content = body.message;
                        successMessageObj.visible = true;
                    }, 1000);
                    setTimeout(() => {
                        successMessageObj.visible = false;
                    }, 5000);
                }
                if ((body.warningVisible)) {
                    warningMessageObj.content = body.message;
                    warningMessageObj.visible = true;
                }
                if (body.errorVisible) {
                    errorMessageObj.content = body.message;
                    errorMessageObj.visible = true;
                }
            });
    };

    const blobToBase64 = (blob: Blob): Promise<string> => {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result as string);
            reader.onerror = reject;
            reader.readAsDataURL(blob);
        })
    }

    const setActiveTab = (index: number): void => {
        if (activeTab === index) {
            return;
        }
        activeTab = index;
        createNewHeader.classList.remove('active');
        existingFieldHeader.classList.remove('active');
        if (activeTab === 0) {
            createNewGroup.hidden = false;
            existingFieldGroup.hidden = true;
            createNewHeader.classList.add('active');
        }
        else if (activeTab === 1) {
            createNewGroup.hidden = true;
            existingFieldGroup.hidden = false;
            existingFieldHeader.classList.add('active');
        }
    }

    const toolbarClickHandler = (args: any) => {
        if (args.item.id === 'visibleSign_download') {
            viewer.download();
        }
    };

    const hideSignImagesGroup = (isHide: boolean = false) => {
        addSignaturebutton.element.parentElement.hidden = isHide;
        const signImagesGroup = document.getElementById('visibleSign_uploaded_images') as HTMLDivElement;
        if (!isNullOrUndefined(signImagesGroup)) {
            signImagesGroup.hidden = isHide;
        }
    }

    const handleCheckboxChange = (field: CheckboxFields, checked: boolean): void => {
        if (checked) {
            descriptionCheckboxes[field].element.
                parentElement.querySelector('.e-label').classList.remove('e-disabled');    
        }
        else {
            descriptionCheckboxes[field].element.
                parentElement.querySelector('.e-label').classList.add('e-disabled');
        }
        descriptionTextboxes[field].enabled = checked;
    }

    const handleSignImagesVisibility = (isChecked: boolean): void => {
        hideSignImagesGroup(!isChecked);
        displayModeDropdown.enabled = isChecked;
        if (isChecked) {
            displayModeDropdown.value = displayModes[1];
        }
        else {
            displayModeDropdown.value = displayModes[2];
        }
    }

    const browseOpen = (args: any): void => {
        const browseButton = select('#e-pv-visible-sign-image-uploader .e-file-select-wrap button', document) as HTMLElement;
        if (!isNullOrUndefined(browseButton)) {
            browseButton.click();
        }
        args.preventDefault();
    }

    const handleImageClick = (args: MouseEvent, index: number): void => {
        selectedImageIndex = index;
        renderImageList(true);
    }

    const handleDeleteImage = (args: MouseEvent, index: number): void => {
        args.stopPropagation();
        if (index <= 0) {
            return;
        }
        imageUrls.splice(index, 1);
        if (selectedImageIndex >= index) {
            selectedImageIndex--;
        }
        renderImageList(true, index);
    }

    const createImageDiv = (index: number, parentElement: HTMLElement): void => {
        const imageDiv = createElement('div', { className: 'e-pv-visible-sign-image-wrapper' });
        imageDiv.setAttribute('data-index', index.toString());
        imageDiv.onclick = function (args) { handleImageClick(args, Number((this as HTMLDivElement).getAttribute('data-index'))) }
        const buttonDiv = createElement('button', { className: 'e-pv-visible-sign-image-delete' }) as HTMLButtonElement;
        buttonDiv.onclick = function (args) { handleDeleteImage(args, Number((this as HTMLDivElement).parentElement.getAttribute('data-index'))) }
        const buttonObj = new Button({
            iconCss: 'e-icons e-close',
            cssClass: 'e-round'
        });
        const imageElem = createElement('img') as HTMLImageElement;
        imageElem.src = imageUrls[index];
        imageElem.alt = `Signature ${index + 1}`;
        parentElement.appendChild(imageDiv);
        imageDiv.appendChild(buttonDiv);
        buttonObj.appendTo(buttonDiv);
        imageDiv.appendChild(imageElem);
    }

    const renderImageList = (isRerender: boolean = false, removedIndex?: number): void | HTMLElement => {
        if (isRerender) {
            const imageLists = selectAll('.e-pv-visible-sign-uploaded-images') as HTMLElement[];
            imageLists.forEach((imageList: HTMLElement) => {
                let imageDivsLength = imageList.children.length;
                while (imageDivsLength < imageUrls.length) {
                    createImageDiv(imageDivsLength, imageList);
                    imageDivsLength = imageList.children.length;
                }
                while (imageDivsLength > imageUrls.length) {
                    if (removedIndex <= 0 || removedIndex >= imageDivsLength) {
                        removedIndex = imageDivsLength - 1;
                    }
                    imageList.removeChild(imageList.children[removedIndex as number]);
                    imageDivsLength = imageList.children.length;
                }
                const imageElements = Array.from(imageList.children) as HTMLElement[];
                imageElements.forEach((element, i) => {
                    element.setAttribute('data-index', i.toString());
                    element.classList.toggle('selected', i === selectedImageIndex);
                })
            })
        }
        else {
            const imageList = createElement('div', { className: 'e-pv-visible-sign-uploaded-images' });
            imageUrls.forEach((_, index: number) => {
                createImageDiv(index, imageList);
            });
            return imageList;
        }
    }

    const getRequestBody = (pdfData: string): any => {
        const jsonObject: any = {
            pdfdata: pdfData,
            signatureType: (signatureTypeDropdown.value as string).toUpperCase(),
            displayMode: (displayModeDropdown.value as string).toUpperCase(),
            digestAlgorithm: (digestAlgorithmDropdown.value as string).toUpperCase()
        };
        if (signatureImageCheckbox.checked && ((displayModeDropdown.value as string) != displayModes[2])) {
            const selectedImageData = imageUrls[selectedImageIndex];
            jsonObject['imagedata'] = selectedImageData;
        }
        if (descriptionCheckboxes['signer'].checked) {
            jsonObject['signerName'] = descriptionTextboxes['signer'].value as string;
        }
        if (descriptionCheckboxes['reason'].checked) {
            jsonObject['reason'] = descriptionTextboxes['reason'].value as string;
        }
        if (descriptionCheckboxes['location'].checked) {
            jsonObject['location'] = descriptionTextboxes['location'].value as string;
        }
        if (descriptionCheckboxes['date'].checked) {
            jsonObject['date'] = formatDate(descriptionTextboxes['date'].value as Date);
        }

        if (activeTab === 0) { // Create new
            jsonObject['isSignatureField'] = false;
            jsonObject['signatureBounds'] = JSON.stringify({
                x: xTextBox.value,
                y: yTextBox.value,
                height: heightTextBox.value,
                width: widthTextBox.value
            });
        }
        else { // choose existing
            jsonObject['isSignatureField'] = true;
        }
        return jsonObject;
    }

    const signDocument = async () => {
        try {
            const pdfBlobData: Blob = await viewer.saveAsBlob();
            const fileReader = new FileReader();
            fileReader.readAsDataURL(pdfBlobData);
            fileReader.onload = (event) => {
                const pdfData = event.target ? event.target.result : '' as string;
                const request = new XMLHttpRequest();
                const jsonObject = getRequestBody(pdfData as string);
                const requestData = JSON.stringify(jsonObject);
                request.open('POST', 'http://localhost:62527/api/pdfviewer/AddVisibleSignature', true);
                request.setRequestHeader('Content-type', 'application/json charset=UTF-8');
                request.onload = () => {
                    if (request.status === 200) {
                        documentData = request.responseText;
                        viewer.load(request.responseText, null);
                        viewer.fileName = fileName;
                        viewer.downloadFileName = fileName;
                        signDocumentButton.disabled = true;
                    }
                };
                request.onerror = () => {
                    console.error('Error in server', request.statusText);
                };
                request.send(requestData);
            };
            fileReader.onerror = () => {
                console.error('Error reading blob as base 64', fileReader.error);
            };
        }
        catch(error: any) {
            console.error('Error converting blob', error);
        }
    };

    if (!isNullOrUndefined(document.querySelector('.e-pv-visible-sign-uploaded-images'))) {
        const defaultImageContainer = document.querySelector('.e-pv-visible-sign-uploaded-images') as HTMLElement;
        if (defaultImageContainer.children.length == 1) {
            (defaultImageContainer.children[0].children[0] as HTMLImageElement).src = defaultSignImage;
            (defaultImageContainer.children[0] as HTMLElement).onclick = (args) => handleImageClick(args, 0);
        }
    }

    const pdfViewerToolbar: Toolbar = new Toolbar({
        items: [
            { prefixIcon: 'e-icons e-download', tooltipText: 'Download', id: 'visibleSign_download', disabled: true, align: 'Right', cssClass: 'e-pv-download-document-container' },
        ],
        clicked: (args) => toolbarClickHandler(args)
    });
    pdfViewerToolbar.appendTo('#visibleSign_pdfViewer_toolbar');

    const uploaderObj: Uploader = new Uploader({
        allowedExtensions: '.jpg,.jpeg,.png',
        dropArea: '.e-pv-visible-sign-tab-panel',
        asyncSettings: uploaderApiPath,
    });
    uploaderObj.success = async (args: SuccessEventArgs): Promise<void> => {
        const fileData = args.file?.rawFile;
        if (fileData instanceof Blob) {
            const imageBase64 = await blobToBase64(fileData);
            uploaderObj.clearAll();
            imageUrls.push(imageBase64);
            selectedImageIndex = imageUrls.length - 1;
            renderImageList(true);
        } else {
            console.error('Unexpected file data type:', typeof fileData);
        }
    }
    uploaderObj.appendTo('#visibleSign_uploader');

    const xTextBox: NumericTextBox = new NumericTextBox({
        showSpinButton: false,
        placeholder: '24',
        format: '###.##',
        min: 0,
        value: x,
        change: (args) => { x = args.value }
    });
    xTextBox.appendTo('#visibleSign_numerictextbox_x');

    const yTextBox: NumericTextBox = new NumericTextBox({
        showSpinButton: false,
        placeholder: '12',
        format: '###.##',
        min: 0,
        value: y,
        change: (args) => { y = args.value }
    });
    yTextBox.appendTo('#visibleSign_numerictextbox_y');

    const widthTextBox: NumericTextBox = new NumericTextBox({
        placeholder: '200',
        format: '###.##',
        min: 0,
        value: width,
        change: (args) => { width = args.value }
    });
    widthTextBox.appendTo('#visibleSign_numerictextbox_width');

    const heightTextBox: NumericTextBox = new NumericTextBox({
        placeholder: '120',
        format: '###.##',
        min: 0,
        value: height,
        change: (args) => { height = args.value }
    });
    heightTextBox.appendTo('#visibleSign_numerictextbox_height');

    const existingFieldDropdown: DropDownList = new DropDownList({
        dataSource: ['Signature Field 1'],
        value: 'Signature Field 1',
        placeholder: 'Select Existing Field'
    });
    existingFieldDropdown.appendTo('#visibleSign_dropdown_existingField');

    const signatureImageCheckbox: CheckBox = new CheckBox({
        label: 'Signature Image',
        checked: true,
        change: (args) => handleSignImagesVisibility(args.checked as boolean)
    });
    signatureImageCheckbox.appendTo('#visibleSign_checkbox_signatureImage');

    const addSignaturebutton: Button = new Button({
        cssClass: 'e-outline',
        isPrimary: true
    });
    addSignaturebutton.appendTo('#visibleSign_button_addSignature');
    addSignaturebutton.element.onclick = (args: any) => { browseOpen(args) };

    ['signer', 'reason', 'location', 'date'].forEach((field: CheckboxFields) => {
        descriptionCheckboxes[field] = new CheckBox({
            checked: true,
            label: `Show ${field}`,
            change: (args) => handleCheckboxChange(field, args.checked)
        });
        descriptionCheckboxes[field].appendTo('#visibleSign_checkbox_' + field);
        if (field == 'date') {
            const todayDate: Date = new Date();
            descriptionTextboxes[field] = new DatePicker({
                placeholder: 'Enter ' + field,
                value: new Date(defaultDescriptionValues[field as CheckboxFields]),
                enabled: true,
                format: 'MM-dd-yyyy',
                allowEdit: false,
                max: new Date(todayDate.getFullYear(), todayDate.getMonth(), todayDate.getDate()),
                showClearButton: false
            });
            descriptionTextboxes[field].appendTo('#visibleSign_datepicker');
        }
        else {
            descriptionTextboxes[field] = new TextBox({
                placeholder: 'Enter ' + field,
                value: defaultDescriptionValues[field as CheckboxFields],
                enabled: true
            });
            descriptionTextboxes[field].appendTo('#visibleSign_textbox_' + field);
        }
    });

    const displayModeDropdown: DropDownList = new DropDownList({
        dataSource: displayModes,
        value: displayModes[1],
        placeholder: 'Select display mode',
        change: (args) => displayMode = args.value as string
    });
    displayModeDropdown.appendTo('#visibleSign_dropdown_displayMode');

    const signatureTypeDropdown: DropDownList = new DropDownList({
        dataSource: ['CAdES', 'CMS'],
        value: signatureType,
        placeholder: 'Select signature type',
        change: (args) => signatureType = args.value as string
    });
    signatureTypeDropdown.appendTo('#visibleSign_dropdown_signatureType');

    const digestAlgorithmDropdown: DropDownList = new DropDownList({
        dataSource: digestAlgorithms,
        value: digestAlgorithm,
        placeholder: 'Select digest algorithm',
        change: (args) => digestAlgorithm = args.value as string
    });
    digestAlgorithmDropdown.appendTo('#visibleSign_dropdown_digestAlgorithm');

    const signDocumentButton: Button = new Button({
        cssClass: 'e-primary'
    });
    signDocumentButton.appendTo('#visibleSign_button_signDocument');
    signDocumentButton.element.onclick = () => signDocument();
